<?php
namespace App\Models;
use App\Enums\LoanApplicationStatus; use App\Models\Concerns\BelongsToTenant; use App\Models\Concerns\HasAuditTrail; use Illuminate\Database\Eloquent\Concerns\HasUlids; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\Relations\HasOne;
class LoanApplication extends Model { use BelongsToTenant,HasAuditTrail,HasUlids; protected $fillable=['cooperative_id','member_id','loan_product_id','approval_workflow_id','reference','requested_principal_minor','tenure','purpose','status','preferred_bank_account_id','applicant_snapshot','policy_snapshot','current_approval_sequence','submitted_at','approved_at','rejected_at','created_by']; protected function casts():array{return ['requested_principal_minor'=>'integer','tenure'=>'integer','status'=>LoanApplicationStatus::class,'applicant_snapshot'=>'array','policy_snapshot'=>'array','current_approval_sequence'=>'integer','submitted_at'=>'datetime','approved_at'=>'datetime','rejected_at'=>'datetime'];} public function member():BelongsTo{return $this->belongsTo(Member::class);}public function product():BelongsTo{return $this->belongsTo(LoanProduct::class,'loan_product_id');}public function workflow():BelongsTo{return $this->belongsTo(ApprovalWorkflow::class,'approval_workflow_id');}public function assessments():HasMany{return $this->hasMany(LoanAssessment::class);}public function guarantors():HasMany{return $this->hasMany(LoanApplicationGuarantor::class);}public function decisions():HasMany{return $this->hasMany(LoanApprovalDecision::class);}public function loan():HasOne{return $this->hasOne(Loan::class);}}
